import{_ as e,o as t,c as s,at as n}from"./chunks/framework.D0_TLDYh.js";const u=JSON.parse('{"title":"ev-abci Overview","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ev-abci Overview | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-abci/overview.md","filePath":"ev-abci/overview.md","lastUpdated":1772446570000}'),i={name:"ev-abci/overview.md"};function o(r,a,l,c,p,d){return t(),s("div",null,a[0]||(a[0]=[n(`<h1 id="ev-abci-overview" tabindex="-1">ev-abci Overview <a class="header-anchor" href="#ev-abci-overview" aria-label="Permalink to &quot;ev-abci Overview&quot;">​</a></h1><p>ev-abci is an ABCI adapter that allows Cosmos SDK applications to run on Evolve instead of CometBFT.</p><h2 id="what-is-ev-abci" tabindex="-1">What is ev-abci? <a class="header-anchor" href="#what-is-ev-abci" aria-label="Permalink to &quot;What is ev-abci?&quot;">​</a></h2><p>ev-abci provides:</p><ul><li><strong>Drop-in replacement</strong> — Swap CometBFT for Evolve with minimal code changes</li><li><strong>ABCI compatibility</strong> — Your existing Cosmos SDK modules work unchanged</li><li><strong>CometBFT RPC compatibility</strong> — Existing clients and tooling continue to work</li><li><strong>Migration tooling</strong> — Migrate existing chains from CometBFT to Evolve</li></ul><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│            Your Cosmos App              │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────┐    │</span></span>
<span class="line"><span>│  │     Cosmos SDK Modules          │    │</span></span>
<span class="line"><span>│  │  (bank, staking, gov, etc.)     │    │</span></span>
<span class="line"><span>│  └─────────────────────────────────┘    │</span></span>
<span class="line"><span>│                  │ ABCI                 │</span></span>
<span class="line"><span>│  ┌───────────────▼─────────────────┐    │</span></span>
<span class="line"><span>│  │           ev-abci               │    │</span></span>
<span class="line"><span>│  │   (ABCI adapter + RPC server)   │    │</span></span>
<span class="line"><span>│  └───────────────┬─────────────────┘    │</span></span>
<span class="line"><span>└──────────────────┼──────────────────────┘</span></span>
<span class="line"><span>                   │ Executor Interface</span></span>
<span class="line"><span>┌──────────────────▼──────────────────────┐</span></span>
<span class="line"><span>│              ev-node                    │</span></span>
<span class="line"><span>│       (consensus + DA + P2P)            │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre></div><p>ev-abci implements the Executor interface, translating ev-node&#39;s calls into ABCI calls to your application.</p><h2 id="key-differences-from-cometbft" tabindex="-1">Key Differences from CometBFT <a class="header-anchor" href="#key-differences-from-cometbft" aria-label="Permalink to &quot;Key Differences from CometBFT&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>CometBFT</th><th>ev-abci</th></tr></thead><tbody><tr><td>Validators</td><td>Multiple validators with staking</td><td>Single sequencer</td></tr><tr><td>Consensus</td><td>BFT consensus rounds</td><td>Sequencer produces blocks</td></tr><tr><td>Finality</td><td>Instant (BFT)</td><td>Soft (P2P) → Hard (DA)</td></tr><tr><td>Block time</td><td>~6s typical</td><td>Configurable (100ms+)</td></tr><tr><td>Vote extensions</td><td>Supported</td><td>Not supported</td></tr></tbody></table><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><ul><li><strong>No validator coordination</strong> — Single sequencer eliminates consensus overhead</li><li><strong>Faster blocks</strong> — No BFT round-trips, blocks as fast as 100ms</li><li><strong>DA-secured</strong> — Security from data availability, not validator set</li><li><strong>Simpler operations</strong> — No validator management, slashing, or jailing</li></ul><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h2><ul><li><strong>Single sequencer</strong> — One node produces blocks (with forced inclusion for censorship resistance)</li><li><strong>Different finality model</strong> — Soft confirmation before DA finality</li><li><strong>No vote extensions</strong> — ABCI++ vote extensions not available</li></ul><h2 id="modules" tabindex="-1">Modules <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;Modules&quot;">​</a></h2><p>ev-abci includes helper modules for migration:</p><ul><li><a href="/ev-abci/modules/staking-wrapper">Staking Wrapper</a> — Prevents validator updates during migration</li><li><a href="/ev-abci/modules/migration-manager">Migration Manager</a> — Handles validator set transition</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/evstack/ev-abci" target="_blank" rel="noreferrer">github.com/evstack/ev-abci</a></li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/getting-started/cosmos/quickstart">Cosmos SDK Quickstart</a> — Get started</li><li><a href="/ev-abci/integration-guide">Integration Guide</a> — Manual integration</li><li><a href="/ev-abci/migration-from-cometbft">Migration from CometBFT</a> — Migrate existing chain</li></ul>`,21)]))}const v=e(i,[["render",o]]);export{u as __pageData,v as default};
